from pyspark.sql.types import StructType, StructField, StringType, DoubleType
schema = StructType([StructField('meter_id', StringType()), StructField('daily_kw', DoubleType()), StructField('region', StringType())])
df_empty = spark.createDataFrame([], schema)
try:
    result_empty = check_region_coverage(df_empty, ['NORTH','SOUTH','EAST','WEST'])
    assert set(result_empty) == {'NORTH','SOUTH','EAST','WEST'}
except Exception as e:
    assert False, f'Crashed on empty DataFrame: {e}'

